import dataclasses
from typing import Optional

@dataclasses.dataclass
class CostTracker:
    model: str
    budget_usd: Optional[float] = None  # hard cap per session; None = unlimited
    _total: float = dataclasses.field(default=0.0, init=False)
    _calls: list = dataclasses.field(default_factory=list, init=False)

    def record(self, input_tokens: int, output_tokens: int) -> float:
        call_cost = cost_usd(self.model, input_tokens, output_tokens)
        self._total += call_cost
        self._calls.append({
            "input_tokens": input_tokens,
            "output_tokens": output_tokens,
            "cost_usd": call_cost,
            "running_total": self._total,
        })
        if self.budget_usd is not None and self._total > self.budget_usd:
            raise BudgetExceededError(
                f'Session cost ${self._total:.4f} exceeded cap ${self.budget_usd:.4f}'
            )
        return call_cost

    @property
    def total_usd(self) -> float:
        return self._total

    @property
    def calls(self) -> list:
        return list(self._calls)


class BudgetExceededError(RuntimeError):
    pass

// costMeter.mjs
// Works with the openai npm package (>= 4.x)

const MODEL_RATES_PER_M = {
  "gpt-4o":      { input: 2.50, output: 10.00 },
  "gpt-4o-mini": { input: 0.15, output:  0.60 },
  "claude-3-5-sonnet-20241022": { input: 3.00, output: 15.00 },
};

export class CostMeter {
  constructor(model, budgetUsd = null) {
    this.model = model;
    this.budgetUsd = budgetUsd;
    this.totalUsd = 0;
    this.calls = [];
  }

  record(inputTokens, outputTokens, meta = {}) {
    const rates = MODEL_RATES_PER_M[this.model];
    if (!rates) throw new Error(`Unknown model: ${this.model}`);
    const callCost = (inputTokens * rates.input + outputTokens * rates.output) / 1e6;
    this.totalUsd += callCost;
    const entry = { inputTokens, outputTokens, callCost, total: this.totalUsd, ...meta };
    this.calls.push(entry);

    // Structured log — forward to your observability pipeline
    console.log(JSON.stringify({ event: "llm_call_cost", ...entry }));

    if (this.budgetUsd !== null && this.totalUsd > this.budgetUsd) {
      throw new Error(`Budget exceeded: $${this.totalUsd.toFixed(6)} > $${this.budgetUsd}`);
    }
    return callCost;
  }

  summary() {
    return {
      model: this.model,
      calls: this.calls.length,
      totalInputTokens: this.calls.reduce((s, c) => s + c.inputTokens, 0),
      totalOutputTokens: this.calls.reduce((s, c) => s + c.outputTokens, 0),
      totalUsd: this.totalUsd,
    };
  }
}

// -- Usage in an agent loop ------------------------------------------
import OpenAI from "openai";

const openai = new OpenAI();
const meter = new CostMeter("gpt-4o-mini", /* budgetUsd= */ 0.10);
const messages = [{ role: "system", content: "You are a concise assistant." }];

async function agentTurn(userMsg) {
  messages.push({ role: "user", content: userMsg });
  const resp = await openai.chat.completions.create({ model: meter.model, messages });
  const { prompt_tokens, completion_tokens } = resp.usage;
  meter.record(prompt_tokens, completion_tokens, { turn: messages.length });
  const reply = resp.choices[0].message.content;
  messages.push({ role: "assistant", content: reply });
  return reply;
}

